var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"사원의 절반이 날아가 버렸군…….","JPN":"寺院の半分が吹っ飛んでしまったな……","ENG":"Half of the temple has been obliterated...","TWN":"一半的修道院都被蒸發了……"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"엄청난 위력이야. 마지막까지 이런 비장의 수를 숨기고 있었다니…….","JPN":"凄まじい威力だ。最後までこんな奥の手を隠していたとは……","ENG":"Such incredible power. I can't believe he kept a secret weapon like this until the end...","TWN":"好強的威力。沒想到竟然把這樣的殺手鐧藏到了最後……"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그보다 이런 폭발에 휘말렸다면 두 사람은 아마도…… ","JPN":"それよりこんな爆発に巻き込まれたということは、おそらくあの二人は…… ","ENG":"And the two who got caught up in that explosion should be...","TWN":"比起這個，如果被這樣的爆炸波及到，那兩個人恐怕已經……"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"으음?","JPN":"うむ？","ENG":"Hmm?","TWN":"額嗯？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……또 날 속였군요, 애버라인.","JPN":"……また私を騙しましたね、アバーライン。","ENG":"...You fooled me again, Abberline.","TWN":"……你又騙我！艾伯林！"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 정도로 위험하다는 말은 없었잖아요! 드레스가 타버려서 엉망이 되어버렸다고요!","JPN":"こんなに危険だなんて聞いてません！　ドレスが焦げてめちゃくちゃになったじゃないですか！","ENG":"You didn't say that it would be this dangerous! Look at my dress! It's all burnt and a mess!","TWN":"沒說會這麼危險啊！我的裙子都燒壞了，變得一團糟了！"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 이해해주게. 스완.","JPN":"はは、理解してくれ。スワン。","ENG":"Haha, forgive me, Swan.","TWN":"哈哈，請理解一下，史旺。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"교수의 마도구에 대해 사실대로 말하면, 자네의 연기가 흔들릴지도 몰랐거든.","JPN":"教授の魔道具について本当のことを話したら、君の演技が揺らいでしまうかもしれないからな。","ENG":"But if I told you about Professor's Curio, I thought your acting would falter.","TWN":"我擔心如實說出，可能會影響你的演技。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말이지! 대체 절 뭐라고 생각하는 건가요!","JPN":"もう！　私をなんだと思ってるんですか！","ENG":"Ugh! Who do you think I am?!","TWN":"呃！你到底把我當成什麼了！"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저는 런던 최고의 프리마돈나라고요! 겨우 이 정도 <color=#ffd34c>각본</color>도 소화 못할 리 없잖아요!","JPN":"私はロンドン最高のプリマドンナ！　たかがこの程度の<color=#ffd34c>脚本</color>も演じられないわけないでしょう！","ENG":"I am London's best prima donna! You know there is no <color=#ffd34c>script</color> too difficult for me!","TWN":"我是倫敦最棒的女主角！區區這種程度的<color=#ffd34c>劇本</color>，我怎麼可能演不好！"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하, 하하……. 잠시나마 자네 걱정을 했던 내가 바보였군, 친구.","JPN":"は、はは……少しでも君を心配した俺がバカだったな、友よ。","ENG":"Ha, haha... I was a fool to worry about you for even a moment, my friend.","TWN":"哈，哈哈……竟然一瞬間擔心你了，我真是個傻瓜，朋友。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 역시 물어봐 주는 게 예의겠지? 대체 어떻게 그 폭발에서 빠져나온 건가?","JPN":"だが、やはり聞いてやらないと失礼だろうな。いったいどうやってあの爆発から抜け出せたんだ？","ENG":"But I should still ask. How did you get away from that explosion?","TWN":"但還是問一下比較禮貌吧？你到底是怎麼從那場爆炸中逃出來的？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 간단한 이야기라네, 벗이여.","JPN":"ふふ、実に簡単な話だよ、旧友。","ENG":"Haha. Elementary, my dear friend.","TWN":"哈哈，很簡單的推理，我親愛的華生。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나는 처음부터 궁지에 몰린 모리어티 교수가 스완을 노릴 것이라는 걸 알고 있었다네.","JPN":"私は最初から予想していたのさ。窮地に追い込まれたモリアーティ教授は、スワンを狙うだろうと。","ENG":"I knew from the start that the embattled Professor Moriarty would target Swan.","TWN":"我從一開始就知道被逼入絕境的莫里蒂教授會盯上史旺。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모리어티 교수는 그녀가 나에게 있어서 중요한 존재라고 확신하고 있었으니까.","JPN":"モリアーティ教授は、彼女が私にとって大事な存在だと確信していたからな。","ENG":"Professor Moriarty was convinced that she was important to me.","TWN":"因為莫里蒂教授確定她對我來說是重要的存在。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 늘 그렇듯, 확신은 독이 되고 시야를 흐리게 만들지.","JPN":"だが、確信というものは、時に毒となり視野を狭くする。","ENG":"But, as always, confidence is poisonous and clouds judgment.","TWN":"但一如既往，確定會成為毒藥，使判斷變得模糊。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 미리 스완에게 이 사실을 알리고, 인질 연기를 지시해 둔 거라네.","JPN":"だから、あらかじめスワンにこの事実を伝え、人質の演技を指示しておいたのだ。","ENG":"I informed Swan of this fact ahead of time, and told her to act as a hostage.","TWN":"所以我提前告訴了史旺這個事實，並指示她配合人質表演。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마도구가 발동하기 직전에 빈틈을 만들어 낼 수 있도록.","JPN":"魔道具が発動する直前に隙を作れるようにな。","ENG":"So that right before he activated the Curio, there would be an opening.","TWN":"這樣就可以在魔導具發動之前製造一個空隙。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"빈틈이라고?","JPN":"隙だと？","ENG":"An opening?","TWN":"空隙嗎？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"거울이에요.","JPN":"鏡です。","ENG":"It's the Mirror.","TWN":"這是面鏡子。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"거울로 무대 조명을 모방해서, 모리어티 교수가 스포트라이트를 받게 만들었죠.","JPN":"鏡で舞台の照明に模倣して、モリアーティ教授がスポットライトを浴びるようにしたんです。","ENG":"I used the Mirror to imitate the spotlight and shine it on Professor Moriarty.","TWN":"我用鏡子模仿了舞台燈光，讓莫里蒂教授成為了焦點。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무대에서는 종종 그런 식으로 클라이맥스를 연출하기도 하거든요.","JPN":"舞台ではよくそのようにクライマックスを演出したりするんですよ。","ENG":"It's a frequent technique used to express the climax on stage.","TWN":"在舞台上，經常會用那種方式來製造高潮。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군. 그 섬광은 교수의 마도구가 아니라, 스완 양의 마도구였어.","JPN":"そうか。あのフラッシュは教授の魔道具ではなく、スワンさんの魔道具だったのだな。","ENG":"I see. So that flash wasn't from Professor's Curio, but from Swan's.","TWN":"原來如此。那道閃光不是教授，而是史旺的魔法道具造成的。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"무대 조명으로 잠시 교수의 눈을 멀게 만들어, 그 사이 자네가 스완 양을 구해냈군.","JPN":"舞台の照明でしばらく教授の目を暗まし、その間に君がスワンさんを助けたというわけか。","ENG":"After blinding him with the stage light, you went to save Swan.","TWN":"用舞台燈光暫時讓教授失明，這期間你救出了史旺。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};